#!/usr/bin/env python3\n\"\"\"\nCustom Gateway Manager for Beast Mode\nEasily add, manage, and extend payment gateway coverage\n\"\"\"\n\nimport json\nimport os\nfrom typing import Dict, List\nfrom rich.console import Console\nfrom rich.table import Table\nfrom rich.panel import Panel\n\nconsole = Console()\n\nclass CustomGatewayManager:\n    \"\"\"Manage custom payment gateways\"\"\"\n    \n    def __init__(self, config_file='custom_gateways.json'):\n        self.config_file = config_file\n        self.gateways = self._load_gateways()\n    \n    def _load_gateways(self) -> Dict:\n        \"\"\"Load custom gateways from JSON file\"\"\"\n        if os.path.exists(self.config_file):\n            with open(self.config_file, 'r') as f:\n                return json.load(f)\n        return {}\n    \n    def _save_gateways(self):\n        \"\"\"Save gateways to JSON file\"\"\"\n        with open(self.config_file, 'w') as f:\n            json.dump(self.gateways, f, indent=2)\n    \n    def add_gateway(self, name: str, keywords: List[str], dorks: List[str], \n                   category: str = 'custom', description: str = ''):\n        \"\"\"Add a new custom gateway\"\"\"\n        gateway = {\n            'keywords': keywords,\n            'dorks': dorks,\n            'category': category,\n            'description': description\n        }\n        \n        self.gateways[name.lower()] = gateway\n        self._save_gateways()\n        \n        console.print(\n            f\"[green]✓[/green] Gateway '{name}' added successfully!\",\n            style=\"bold green\"\n        )\n    \n    def remove_gateway(self, name: str):\n        \"\"\"Remove a custom gateway\"\"\"\n        if name.lower() in self.gateways:\n            del self.gateways[name.lower()]\n            self._save_gateways()\n            console.print(\n                f\"[green]✓[/green] Gateway '{name}' removed!\",\n                style=\"bold red\"\n            )\n        else:\n            console.print(f\"[red]✗[/red] Gateway '{name}' not found!\", style=\"red\")\n    \n    def list_gateways(self):\n        \"\"\"Display all custom gateways in a table\"\"\"\n        if not self.gateways:\n            console.print(\"[yellow]No custom gateways configured.[/yellow]\")\n            return\n        \n        table = Table(title=\"[bold cyan]Custom Gateways[/bold cyan]\", show_header=True)\n        table.add_column(\"Gateway Name\", style=\"cyan\")\n        table.add_column(\"Category\", style=\"magenta\")\n        table.add_column(\"Keywords\", style=\"green\")\n        table.add_column(\"Dorks\", style=\"yellow\")\n        table.add_column(\"Description\", style=\"blue\")\n        \n        for name, config in self.gateways.items():\n            keywords = ', '.join(config['keywords'][:2])\n            dorks = f\"{len(config['dorks'])} dorks\"\n            description = config.get('description', '')[:30]\n            \n            table.add_row(\n                name.upper(),\n                config.get('category', 'custom'),\n                keywords,\n                dorks,\n                description\n            )\n        \n        console.print(table)\n    \n    def get_gateway(self, name: str) -> Dict:\n        \"\"\"Get a specific gateway configuration\"\"\"\n        return self.gateways.get(name.lower())\n    \n    def get_all_gateways(self) -> Dict:\n        \"\"\"Get all custom gateways\"\"\"\n        return self.gateways\n    \n    def update_gateway(self, name: str, **kwargs):\n        \"\"\"Update gateway configuration\"\"\"\n        if name.lower() in self.gateways:\n            self.gateways[name.lower()].update(kwargs)\n            self._save_gateways()\n            console.print(\n                f\"[green]✓[/green] Gateway '{name}' updated!\",\n                style=\"bold green\"\n            )\n        else:\n            console.print(f\"[red]✗[/red] Gateway '{name}' not found!\", style=\"red\")\n    \n    def export_gateways(self, filename: str):\n        \"\"\"Export gateways to a file\"\"\"\n        with open(filename, 'w') as f:\n            json.dump(self.gateways, f, indent=2)\n        console.print(\n            f\"[green]✓[/green] Gateways exported to {filename}\",\n            style=\"bold green\"\n        )\n    \n    def import_gateways(self, filename: str):\n        \"\"\"Import gateways from a file\"\"\"\n        if os.path.exists(filename):\n            with open(filename, 'r') as f:\n                imported = json.load(f)\n                self.gateways.update(imported)\n                self._save_gateways()\n                console.print(\n                    f\"[green]✓[/green] Imported {len(imported)} gateways from {filename}\",\n                    style=\"bold green\"\n                )\n        else:\n            console.print(f\"[red]✗[/red] File {filename} not found!\", style=\"red\")\n\n# Pre-configured gateway templates for easy addition\nGATEWAY_TEMPLATES = {\n    'stripe': {\n        'keywords': ['pk_live_', 'stripe.com/checkout', 'stripejs'],\n        'dorks': [\n            'inurl:checkout stripe -site:github.com',\n            '\"pk_live_\" -site:stripe.com',\n            'stripe.js inurl:checkout'\n        ],\n        'category': 'payment_processor',\n        'description': 'Stripe payment processor'\n    },\n    'shopify_payments': {\n        'keywords': ['shopify', 'myshopify', 'shop-pay'],\n        'dorks': [\n            'myshopify.com inurl:checkout -site:github.com',\n            '\"Shopify.checkout\"',\n            'shop-pay.js'\n        ],\n        'category': 'ecommerce',\n        'description': 'Shopify native payments'\n    },\n    'woocommerce': {\n        'keywords': ['woocommerce', 'wp-json/wc'],\n        'dorks': [\n            'woocommerce inurl:checkout -site:github.com',\n            'wp-json/wc/store',\n            '\"WooCommerce checkout\"'\n        ],\n        'category': 'ecommerce',\n        'description': 'WordPress WooCommerce'\n    },\n    'shopware': {\n        'keywords': ['shopware', 'checkout'],\n        'dorks': [\n            'shopware.com inurl:checkout -site:github.com',\n            '\"shopware checkout\"'\n        ],\n        'category': 'ecommerce',\n        'description': 'Shopware commerce platform'\n    },\n    'prestashop': {\n        'keywords': ['prestashop', 'order-confirmation'],\n        'dorks': [\n            'prestashop inurl:order-confirmation -site:github.com',\n            '\"PrestaShop checkout\"'\n        ],\n        'category': 'ecommerce',\n        'description': 'PrestaShop ecommerce'\n    },\n    'magento': {\n        'keywords': ['magento', 'checkout/cart'],\n        'dorks': [\n            'magento inurl:checkout/cart -site:github.com',\n            '\"Mage.checkout\"',\n            'magento.js'\n        ],\n        'category': 'ecommerce',\n        'description': 'Adobe Magento commerce'\n    },\n    'sagepay': {\n        'keywords': ['sagepay', 'op.js'],\n        'dorks': [\n            'sagepay inurl:checkout -site:github.com',\n            '\"sagepay.js\"'\n        ],\n        'category': 'payment_processor',\n        'description': 'Sage Pay payment gateway'\n    },\n    'worldpay': {\n        'keywords': ['worldpay', 'payments.worldpay'],\n        'dorks': [\n            'worldpay inurl:checkout -site:github.com',\n            'payments.worldpay.js'\n        ],\n        'category': 'payment_processor',\n        'description': 'Worldpay payments'\n    },\n    'cybersource': {\n        'keywords': ['cybersource', 'flex-token'],\n        'dorks': [\n            'cybersource inurl:checkout -site:github.com',\n            'flex.cybersource'\n        ],\n        'category': 'payment_processor',\n        'description': 'CyberSource payments'\n    },\n    'openpay': {\n        'keywords': ['openpay', 'checkout.js'],\n        'dorks': [\n            'openpay inurl:checkout -site:github.com',\n            'openpay.js'\n        ],\n        'category': 'payment_processor',\n        'description': 'OpenPay payment gateway'\n    },\n    'trustly': {\n        'keywords': ['trustly', 'bankid'],\n        'dorks': [\n            'trustly inurl:checkout -site:github.com',\n            '\"trustly.js\"'\n        ],\n        'category': 'regional',\n        'description': 'Trustly EU payments'\n    },\n    'giropay': {\n        'keywords': ['giropay', 'bankcode'],\n        'dorks': [\n            'giropay inurl:checkout -site:github.com',\n            'giropay.js'\n        ],\n        'category': 'regional',\n        'description': 'Giropay Germany'\n    },\n    'eps': {\n        'keywords': ['eps', 'easybank'],\n        'dorks': [\n            'eps inurl:checkout -site:github.com',\n            'online-payment-gateway.at'\n        ],\n        'category': 'regional',\n        'description': 'Electronic Payment Standard Austria'\n    },\n    'przelewy24': {\n        'keywords': ['przelewy24', 'p24'],\n        'dorks': [\n            'przelewy24 inurl:checkout -site:github.com',\n            'p24.pl',\n            'przelewy24.js'\n        ],\n        'category': 'regional',\n        'description': 'Przelewy24 Poland'\n    },\n    'bancontact': {\n        'keywords': ['bancontact', 'bcmc'],\n        'dorks': [\n            'bancontact inurl:checkout -site:github.com',\n            'bancontact.js'\n        ],\n        'category': 'regional',\n        'description': 'Bancontact Belgium'\n    },\n    'sofort': {\n        'keywords': ['sofort', 'klarna.sofort'],\n        'dorks': [\n            'sofort inurl:checkout -site:github.com',\n            'klarna.sofort.js'\n        ],\n        'category': 'regional',\n        'description': 'Sofort Bank Transfer'\n    },\n    'multibanco': {\n        'keywords': ['multibanco', 'mbway'],\n        'dorks': [\n            'multibanco inurl:checkout -site:github.com',\n            'mbway.pt'\n        ],\n        'category': 'regional',\n        'description': 'Multibanco Portugal'\n    },\n    'mybank': {\n        'keywords': ['mybank', 'bancomat'],\n        'dorks': [\n            'mybank inurl:checkout -site:github.com',\n            'mybank.it'\n        ],\n        'category': 'regional',\n        'description': 'MyBank Italy'\n    },\n    'postfinance': {\n        'keywords': ['postfinance', 'postomat'],\n        'dorks': [\n            'postfinance inurl:checkout -site:github.com',\n            'postfinance.ch'\n        ],\n        'category': 'regional',\n        'description': 'PostFinance Switzerland'\n    },\n}\n\ndef interactive_gateway_builder():\n    \"\"\"Interactive CLI for building custom gateways\"\"\"\n    manager = CustomGatewayManager()\n    \n    console.print(\n        Panel(\n            \"[bold cyan]🎯 Custom Gateway Manager[/bold cyan]\",\n            expand=False,\n            border_style=\"bold blue\"\n        )\n    )\n    \n    while True:\n        console.print(\"\"\"\n[bold cyan]Options:[/bold cyan]\n1. Add gateway from template\n2. Add custom gateway\n3. List all gateways\n4. Remove gateway\n5. Export gateways\n6. Import gateways\n7. Exit\n        \"\"\")\n        \n        choice = input(\"\\nSelect option (1-7): \").strip()\n        \n        if choice == '1':\n            console.print(\"\\n[bold]Available Templates:[/bold]\")\n            for i, template_name in enumerate(GATEWAY_TEMPLATES.keys(), 1):\n                console.print(f\"{i}. {template_name.upper()}\")\n            \n            template_num = int(input(\"\\nSelect template: \")) - 1\n            template_name = list(GATEWAY_TEMPLATES.keys())[template_num]\n            template = GATEWAY_TEMPLATES[template_name]\n            \n            manager.add_gateway(\n                template_name,\n                template['keywords'],\n                template['dorks'],\n                template['category'],\n                template['description']\n            )\n        \n        elif choice == '2':\n            name = input(\"Gateway name: \")\n            keywords = input(\"Keywords (comma-separated): \").split(',')\n            dorks = input(\"Dorks (comma-separated): \").split(',')\n            category = input(\"Category (default: custom): \") or \"custom\"\n            description = input(\"Description: \")\n            \n            manager.add_gateway(\n                name,\n                [k.strip() for k in keywords],\n                [d.strip() for d in dorks],\n                category,\n                description\n            )\n        \n        elif choice == '3':\n            manager.list_gateways()\n        \n        elif choice == '4':\n            name = input(\"Gateway name to remove: \")\n            manager.remove_gateway(name)\n        \n        elif choice == '5':\n            filename = input(\"Export filename (default: gateways_export.json): \") or \"gateways_export.json\"\n            manager.export_gateways(filename)\n        \n        elif choice == '6':\n            filename = input(\"Import filename: \")\n            manager.import_gateways(filename)\n        \n        elif choice == '7':\n            console.print(\"[green]Goodbye![/green]\")\n            break\n        \n        else:\n            console.print(\"[red]Invalid option![/red]\")\n\nif __name__ == '__main__':\n    interactive_gateway_builder()\n